import React from 'react';
import './Paralax.css'
import {Link} from 'react-router-dom';


function PutParalax() {
  return (
    <div className="parallax">
      <h1>
        Виртуальный тур по городу
      </h1>  
      <Link to="/virtual-map" className="parallax-button">Попробовать</Link>
      <div className="mask"></div>
      
    </div>
    
  );
}

export default PutParalax;